def solve(expr: str) -> int:
    tokens = expr.replace(' ', '')
    pos = [0]

    def peek():
        return tokens[pos[0]] if pos[0] < len(tokens) else None

    def consume():
        c = tokens[pos[0]]
        pos[0] += 1
        return c

    def parse_number():
        start = pos[0]
        if pos[0] >= len(tokens) or not tokens[pos[0]].isdigit():
            raise ValueError("Expected number")
        while pos[0] < len(tokens) and tokens[pos[0]].isdigit():
            pos[0] += 1
        return int(tokens[start:pos[0]])

    def parse_factor():
        if peek() == '(':
            consume()
            val = parse_expression()
            if pos[0] >= len(tokens) or tokens[pos[0]] != ')':
                raise ValueError("Expected ')'")
            consume()
            return val
        return parse_number()

    def parse_expression():
        result = parse_factor()
        while pos[0] < len(tokens) and tokens[pos[0]] in '+-':
            op = consume()
            rhs = parse_factor()
            if op == '+':
                result += rhs
            else:
                result -= rhs
        return result

    return parse_expression()
