def solve(pattern: str, text: str) -> bool:
    m, n = len(pattern), len(text)
    dp = [[False] * (n + 1) for _ in range(m + 1)]
    dp[0][0] = True
    for i in range(1, m + 1):
        if pattern[i - 1] == '*':
            dp[i][0] = dp[i - 1][0]
    for i in range(1, m + 1):
        p = pattern[i - 1]
        for j in range(1, n + 1):
            if p == '*':
                dp[i][j] = dp[i - 1][j] or dp[i][j - 1]
            elif p == '?' or p == text[j - 1]:
                dp[i][j] = dp[i - 1][j - 1]
    return dp[m][n]
```

